import React, { useState, useEffect } from 'react';
import { initializeApp } from 'firebase/app';
import { getDatabase, ref, onValue } from 'firebase/database';

// Initialize Firebase
const firebaseConfig = {
  apiKey: "AIzaSyAvITdQHZkF-Kjkacna0fsxPYqbBEKJwlg",
  authDomain: "fvwl-8109b.firebaseapp.com",
  databaseURL: "https://fvwl-8109b-default-rtdb.europe-west1.firebasedatabase.app",
  projectId: "fvwl-8109b",
  storageBucket: "fvwl-8109b.firebasestorage.app",
  messagingSenderId: "406636067359",
  appId: "1:406636067359:web:8b70673d38495254b2f32a"
};

const app = initializeApp(firebaseConfig);
const database = getDatabase(app);

// Bolton Wanderers Logo Component
function BWFCLogo() {
  const logoBase64 = "data:image/png;base64,";

  return (
    <div style={{
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '20px',
      padding: '10px'
    }}>
      <img
        src={logoBase64}
        alt="Bolton Wanderers FC"
        style={{
          width: '80px',
          height: '80px',
          borderRadius: '50%',
          border: '3px solid #003f7f',
          boxShadow: '0 4px 8px rgba(0,0,0,0.2)',
          cursor: 'pointer'
        }}
      />
    </div>
  );
}

function EnhancedSquadList({ isAuthenticated }) {
  const [players, setPlayers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('All');

  // Load fixture data to calculate goals for each player
  const [fixtures, setFixtures] = useState([]);

  useEffect(() => {
    const fetchFixtures = async () => {
      try {
        const response = await fetch('https://api.jsonbin.io/v3/b/68283e428561e97a50159f75/latest', {
          headers: {
            'X-Master-Key': '$2a$10$VTMAZsuNJaZxXb2dEFdOheJXXwRGD7GJj7e5vRp9jKvHqF51SN29e'
          }
        });
        const data = await response.json();
        setFixtures(data.record);
      } catch (error) {
        console.error('Error fetching fixtures:', error);
      }
    };

    fetchFixtures();
  }, []);

  // Function to get player goals from fixtures
  const getPlayerGoals = (player) => {
    let totalGoals = 0;
    fixtures.forEach(fixture => {
      for (let i = 1; i <= 6; i++) {
        const scorer = fixture[`scorer${i}`];
        if (scorer && scorer.includes(player.forename) && scorer.includes(player.surname)) {
          // Handle multiple goals in format like "M. Forss (20', 50')"
          const matches = scorer.match(/\d+'/g);
          totalGoals += matches ? matches.length : 1;
        }
      }
    });
    return totalGoals;
  };

  // Load players from Firebase
  useEffect(() => {
    const playersRef = ref(database, 'squad2526');
    const unsubscribe = onValue(playersRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const playersArray = Object.values(data).filter(player => player.notes !== 'Total');
        setPlayers(playersArray);
      }
      setLoading(false);
    });

    // Cleanup function to unsubscribe when component unmounts
    return () => unsubscribe();
  }, []);

  // Calculate team totals based on filtered players
  const calculateTeamTotals = (filteredPlayers) => {
    return filteredPlayers.reduce((totals, player) => {
      totals.totalGoals += getPlayerGoals(player);
      return totals;
    }, {
      totalGoals: 0,
      activePlayers: filteredPlayers.length,
      fixturesPlayed: fixtures.length
    });
  };

  if (loading) {
    return <div style={{padding: '20px'}}>Loading squad...</div>;
  }

  // Filter players based on selection
  const filteredPlayers = players.filter(player => {
    if (statusFilter === 'All') return true;
    if (statusFilter === 'Available') return player.notes === 'Squad' || player.notes === 'Loan in';
    return player.notes === statusFilter;
  });

  const teamTotals = calculateTeamTotals(filteredPlayers);

  return (
    <div style={{padding: '20px'}}>
      {/* Bolton Wanderers Logo */}
      <BWFCLogo />

      {/* Squad Header */}
      <div style={{
        fontSize: '32px',
        fontWeight: 'bold',
        color: '#003f7f',
        textAlign: 'center',
        marginBottom: '20px'
      }}>
        Bolton Wanderers FC Squad 2025-26
      </div>

      {/* Status Filter Dropdown */}
      <div style={{
        marginBottom: '20px',
        display: 'flex',
        alignItems: 'center',
        gap: '10px',
        flexWrap: 'wrap'
      }}>
        <label style={{ fontWeight: 'bold', color: '#003f7f' }}>Filter by Status:</label>
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          style={{
            padding: '8px 12px',
            borderRadius: '5px',
            border: '2px solid #003f7f',
            fontSize: '16px',
            backgroundColor: 'white',
            cursor: 'pointer'
          }}
        >
          <option value="All">All Players</option>
          <option value="Squad">Squad</option>
          <option value="Loan in">Loan in</option>
          <option value="On loan">On loan</option>
          <option value="Gone">Gone</option>
          <option value="Available">Available (Squad + Loan in)</option>
        </select>
      </div>

      {/* Team Totals Section */}
      <div style={{
        backgroundColor: '#f0f8ff',
        border: '3px solid #4682b4',
        borderRadius: '10px',
        padding: '20px',
        marginBottom: '30px',
        boxShadow: '0 6px 12px rgba(0,0,0,0.1)',
        background: 'linear-gradient(135deg, #f0f8ff 0%, #e6f3ff 100%)'
      }}>
        <div style={{
          fontSize: '20px',
          fontWeight: 'bold',
          color: '#003f7f',
          marginBottom: '15px',
          textAlign: 'center'
        }}>
          Team Totals ({statusFilter})
        </div>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
          gap: '15px',
          textAlign: 'center'
        }}>
          <div>
            <div style={{fontSize: '28px', fontWeight: 'bold', color: '#1976d2'}}>{teamTotals.totalGoals}</div>
            <div style={{fontSize: '14px', color: '#666'}}>Total Goals</div>
          </div>
          <div>
            <div style={{fontSize: '28px', fontWeight: 'bold', color: '#2e7d32'}}>{teamTotals.activePlayers}</div>
            <div style={{fontSize: '14px', color: '#666'}}>Active Players</div>
          </div>
          <div>
            <div style={{fontSize: '28px', fontWeight: 'bold', color: '#d32f2f'}}>{teamTotals.fixturesPlayed}</div>
            <div style={{fontSize: '14px', color: '#666'}}>Fixtures Played</div>
          </div>
        </div>
      </div>

      {/* Individual Players */}
      {filteredPlayers.filter(player => {
        if (statusFilter === 'All') return true;
        if (statusFilter === 'Available') return player.notes === 'Squad' || player.notes === 'Loan in';
        return player.notes === statusFilter;
      }).map(player => {
        const goals = getPlayerGoals(player);

        return (
          <div key={player.id} style={{
            border: '2px solid #003f7f',
            borderRadius: '10px',
            padding: '15px',
            margin: '10px 0',
            backgroundColor: '#f9f9f9'
          }}>
            <div style={{
              fontSize: '18px',
              fontWeight: 'bold',
              color: '#003f7f',
              marginBottom: '10px'
            }}>
              {player.forename} {player.surname}
            </div>

            {/* Goals and Statistics */}
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))',
              gap: '10px',
              marginBottom: '10px'
            }}>
              <div>
                <strong>Goals:</strong> {goals}
              </div>
              <div>
                <strong>Status:</strong> {player.notes}
              </div>
              {player.DOB && (
                <div>
                  <strong>DOB:</strong> {player.DOB}
                </div>
              )}
            </div>

            {/* Financial Information (only if authenticated) */}
            {isAuthenticated && (
              <div style={{
                backgroundColor: '#fff3cd',
                border: '1px solid #ffc107',
                borderRadius: '5px',
                padding: '10px',
                marginTop: '10px'
              }}>
                <div style={{ fontWeight: 'bold', marginBottom: '5px', color: '#856404' }}>
                  💰 Financial Details (Admin Only)
                </div>
                <div style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: '10px'
                }}>
                  {player.currentWeeklyWage && (
                    <div>
                      <strong>Weekly Wage:</strong> £{player.currentWeeklyWage.toLocaleString()}
                    </div>
                  )}
                  {player.overallTotal && (
                    <div>
                      <strong>Overall Total:</strong> £{player.overallTotal.toLocaleString()}
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        );
      })}

      {filteredPlayers.length === 0 && (
        <div style={{
          textAlign: 'center',
          fontSize: '18px',
          color: '#666',
          marginTop: '40px'
        }}>
          No players found for the selected status.
        </div>
      )}
    </div>
  );
}

export default EnhancedSquadList;
